import React, { createContext, useContext, useState } from 'react';
import { Conversation, Message, StreamingChunk } from '../types/chat';
import { chatApi } from '../api/chat';
import { useAuth } from './AuthContext';

interface ChatContextType {
  conversations: Conversation[];
  currentConversation: Conversation | null;
  messages: Message[];
  isLoading: boolean;
  isStreaming: boolean;
  toolActivity: string;
  createConversation: (title: string) => Promise<void>;
  loadConversations: () => Promise<void>;
  loadMessages: (conversationId: string) => Promise<void>;
  sendMessage: (message: string, conversationId?: string) => Promise<void>;
  setCurrentConversation: (conversation: Conversation | null) => void;
  setToolActivity: (activity: string) => void;
}

const ChatContext = createContext<ChatContextType | undefined>(undefined);

export const useChat = () => {
  const context = useContext(ChatContext);
  if (context === undefined) {
    throw new Error('useChat must be used within a ChatProvider');
  }
  return context;
};

interface ChatProviderProps {
  children: React.ReactNode;
}

export const ChatProvider: React.FC<ChatProviderProps> = ({ children }) => {
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [currentConversation, setCurrentConversation] = useState<Conversation | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isStreaming, setIsStreaming] = useState(false);
  const [toolActivity, setToolActivity] = useState('');
  const { token } = useAuth();

  const createConversation = async (title: string) => {
    try {
      setIsLoading(true);
      const newConversation = await chatApi.createConversation(title);
      setConversations(prev => [newConversation, ...prev]);
      setCurrentConversation(newConversation);
    } catch (error) {
      console.error('Error creating conversation:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const loadConversations = async () => {
    try {
      setIsLoading(true);
      const conversationList = await chatApi.getConversations();
      setConversations(conversationList);
    } catch (error) {
      console.error('Error loading conversations:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const loadMessages = async (conversationId: string) => {
    try {
      setIsLoading(true);
      const messageList = await chatApi.getMessages(conversationId);
      setMessages(messageList);
    } catch (error) {
      console.error('Error loading messages:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const sendMessage = async (message: string, conversationId?: string) => {
    try {
      setIsStreaming(true);
      setToolActivity('');

      const response = await fetch('/api/chat/stream', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({
          message,
          conversation_id: conversationId
        })
      });

      if (!response.ok) {
        throw new Error('Failed to send message');
      }

      const reader = response.body?.getReader();
      if (!reader) throw new Error('No response body');

      const decoder = new TextDecoder();
      let assistantMessage = '';
      let toolCalls: any[] = [];

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const chunk = decoder.decode(value);
        const lines = chunk.split('\n');

        for (const line of lines) {
          if (line.startsWith('data: ')) {
            try {
              const data = JSON.parse(line.slice(6));

              if (data.event === 'message') {
                const messageData = JSON.parse(data.data);

                if (messageData.type === 'content') {
                  assistantMessage = messageData.content || '';
                  toolCalls = messageData.tool_calls || [];
                } else if (messageData.type === 'tool_call') {
                  setToolActivity(prev => prev + `\nUsing tool: ${messageData.tool_name}`);
                } else if (messageData.type === 'error') {
                  assistantMessage = messageData.content || 'An error occurred';
                }
              } else if (data.event === 'done') {
                // Add the assistant message to the messages
                if (assistantMessage) {
                  const newMessage: Message = {
                    id: Date.now().toString(),
                    conversation_id: conversationId || '',
                    user_id: '',
                    role: 'assistant',
                    content: assistantMessage,
                    tool_calls: toolCalls,
                    timestamp: new Date().toISOString()
                  };
                  setMessages(prev => [...prev, newMessage]);
                }

                // Reload conversations to get updated timestamps
                await loadConversations();
              }
            } catch (e) {
              console.error('Error parsing SSE data:', e);
            }
          }
        }
      }
    } catch (error) {
      console.error('Error sending message:', error);
    } finally {
      setIsStreaming(false);
      setToolActivity('');
    }
  };

  const value: ChatContextType = {
    conversations,
    currentConversation,
    messages,
    isLoading,
    isStreaming,
    toolActivity,
    createConversation,
    loadConversations,
    loadMessages,
    sendMessage,
    setCurrentConversation,
    setToolActivity,
  };

  return <ChatContext.Provider value={value}>{children}</ChatContext.Provider>;
};
